SELECT g.id, g.student_id, g.course_id, g.score, g.exam_date, s.name AS student_name, s.student_no, s.class_name, c.course_name FROM t_grade g LEFT JOIN t_student s ON g.student_id = s.id LEFT JOIN t_course c ON g.course_id = c.id
AND g.course_id = #{courseId}
AND (s.name LIKE CONCAT('%', #{keyword}, '%') OR s.student_no LIKE CONCAT('%', #{keyword}, '%'))
AND g.student_id = #{studentId}
ORDER BY g.id DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM t_grade g
LEFT JOIN t_student s ON g.student_id = s.id


        AND g.course_id = #{courseId}


        AND (s.name LIKE CONCAT('%', #{keyword}, '%')
             OR s.student_no LIKE CONCAT('%', #{keyword}, '%'))


        AND g.student_id = #{studentId}
